import React, { useEffect, useState, useRef } from 'https://esm.sh/react@18.2.0';
import ReactDOM from 'https://esm.sh/react-dom@18.2.0/client';
import * as d3 from 'https://cdn.jsdelivr.net/npm/d3@7.8.5/+esm';

const TRACK_BG = '#F8FAFC';

function IZOInteractionTimeline(props) {
  const [isLoaded, setIsLoaded] = useState(false);
  const svgRef = useRef(null);

  useEffect(() => {
    const styleId = 'izo-timeline-donut-aligned-v2';
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.innerHTML = `
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
        html, body { margin: 0; padding: 0; font-family: 'Inter', sans-serif; background: white; }

        .main-wrapper { padding: 32px; position: relative; }

        .header-section { margin-bottom: 12px; }
        .timeline-header-title { font-size: 16px; font-weight: 500; color: #252726; margin: 0; margin-bottom: 8px; }
        .timeline-header-sub { font-size: 14px; color: #252726; font-weight: 400; }

        .izo-tooltip {
          position: absolute; padding: 8px 12px; background: #1e293b; color: #ffffff;
          border-radius: 6px; font-size: 12px; pointer-events: none; opacity: 0;
          z-index: 100; box-shadow: 0 10px 15px -3px rgb(0 0 0 / 0.3); line-height: 1.5;
        }
        .tooltip-row { display: block; }
        .tooltip-value { font-weight: 700; }

        .footer-section { margin-top: 12px; display: flex; flex-direction: column; gap: 16px; }
        .footer-date-label { font-size: 14px; color: #252726; font-weight: 400; }
        .footer-date-value { font-size: 14px; color: #7C858C; font-weight: 600; margin-left: 8px; }

        /* Updated Insight Pill */
        .insight-pill { display: flex; align-items: center; gap: 10px; }
        .insight-icon-container { 
          width: 24px; height: 24px; display: flex; align-items: center; justify-content: center;
          background-color: #F8FAFC; border: 1px solid #F1F5F9; border-radius: 9999px; 
        }
        .insight-text { font-size: 14px; color: #252726; font-weight: 500; }

        .interaction-type-head { font-size: 11px; font-weight: 600; fill: #252726; text-transform: capitalize; }
        .y-label { font-size: 12px; font-weight: 500; fill: #475569; }
        .x-label { font-size: 11px; font-weight: 500; fill: #94A3B8; }
        .header-divider { stroke: #E2E8F0; stroke-width: 1; }
        .pill-count { font-size: 11px; font-weight: 700; fill: #1e293b; text-anchor: middle; dominant-baseline: central; pointer-events: none; }
      `;
      document.head.appendChild(style);
    }
    setIsLoaded(true);
  }, []);

  useEffect(() => {
    if (!isLoaded || !props.data || !props.data.events) return;

    const categories = ['Email', 'Call', 'In person'];
    const margin = { top: 40, right: 10, bottom: 10, left: 120 };
    const width = 850 - margin.left - margin.right;
    const rowHeight = 44; 
    const height = categories.length * rowHeight;

    const container = d3.select(".main-wrapper");
    let tooltip = container.select(".izo-tooltip");
    if (tooltip.empty()) { tooltip = container.append("div").attr("class", "izo-tooltip"); }

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const g = svg
      .attr("viewBox", `0 0 ${width + margin.left + margin.right} ${height + margin.top + margin.bottom}`)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const rangeMonths = parseInt(props.data.rangeMonths) || 6;
    const eventDates = props.data.events.map(d => new Date(d.date + "-02"));
    const baseDate = eventDates.length > 0 ? d3.min(eventDates) : new Date();
    const startDate = d3.timeMonth.floor(baseDate);
    const endDate = d3.timeMonth.offset(startDate, rangeMonths);

    const x = d3.scaleTime().domain([startDate, endDate]).range([0, width]);
    const y = d3.scaleBand().domain(categories).range([0, height]).paddingInner(0.35);

    // Headers
    g.append("text").attr("class", "interaction-type-head").attr("x", -margin.left).attr("y", -20).text("Interaction Type");
    const months = d3.timeMonth.range(startDate, d3.timeMonth.offset(endDate, 1));
    g.selectAll(".header-divider").data(months).enter().append("line")
      .attr("class", "header-divider").attr("x1", d => x(d)).attr("x2", d => x(d)).attr("y1", -30).attr("y2", -10);

    // Tracks
    g.selectAll(".track").data(categories).enter().append("rect")
      .attr("x", 0).attr("y", d => y(d)).attr("width", width).attr("height", y.bandwidth()).attr("rx", 6).attr("fill", TRACK_BG);

    // Labels
    g.selectAll(".y-label").data(categories).enter().append("text")
      .attr("class", "y-label").attr("x", -margin.left).attr("y", d => y(d) + y.bandwidth()/2)
      .attr("alignment-baseline", "middle").text(d => d);

    g.selectAll(".x-label").data(months.slice(0, -1)).enter().append("text")
      .attr("class", "x-label").attr("x", (d, i) => (x(d) + x(months[i+1])) / 2)
      .attr("y", -20).attr("text-anchor", "middle").text(d => d3.timeFormat("%b %Y")(d));

    // Interaction Pills
    const columnWidth = width / rangeMonths;
    const maxCount = d3.max(props.data.events, d => d.count) || 1;
    const sizeScale = d3.scaleLinear().domain([0, maxCount]).range([32, columnWidth * 0.85]);
    const colorMap = { 'Email': '#29D1F1', 'Call': '#86EFAC', 'In person': '#BEF264' };

    const pillGroups = g.selectAll(".pill-group").data(props.data.events).enter().append("g")
      .attr("transform", d => {
        const mStart = x(d3.timeMonth.floor(new Date(d.date + "-02")));
        const pWidth = sizeScale(d.count);
        return `translate(${mStart + (columnWidth/2) - (pWidth/2)}, ${y(d.type)})`;
      });

    pillGroups.append("rect")
      .attr("width", d => sizeScale(d.count)).attr("height", y.bandwidth()).attr("rx", 6)
      .attr("fill", d => colorMap[d.type] || '#CBD5E1').style("cursor", "pointer")
      .on("mouseover", function(event, d) {
        d3.select(this).attr("opacity", 0.85);
        tooltip.style("opacity", 1).html(`
            <span class="tooltip-row">${d.type}: <span class="tooltip-value">${d.count}</span></span>
            <span class="tooltip-row">${d3.timeFormat("%B %Y")(new Date(d.date + "-02"))}</span>
        `);
      })
      .on("mousemove", function(event) {
        const [mx, my] = d3.pointer(event, document.body);
        tooltip.style("left", (mx + 15) + "px").style("top", (my - 50) + "px");
      })
      .on("mouseout", function() {
        d3.select(this).attr("opacity", 1);
        tooltip.style("opacity", 0);
      });

    pillGroups.append("text")
      .attr("x", d => sizeScale(d.count) / 2).attr("y", y.bandwidth() / 2)
      .attr("class", "pill-count").text(d => d.count);

  }, [isLoaded, props.data]);

  return React.createElement('div', { className: "main-wrapper" },
    React.createElement('div', { className: "header-section" },
      React.createElement('h3', { className: "timeline-header-title" }, props.data?.title || "Interaction Timeline"),
      React.createElement('p', { className: "timeline-header-sub" }, props.data?.subtitle)
    ),
    React.createElement('svg', { ref: svgRef, style: { width: '100%', height: 'auto' } }),
    React.createElement('div', { className: "footer-section" },
      React.createElement('div', { className: "footer-date-label" },
        "Last Interaction date",
        React.createElement('span', { className: "footer-date-value" }, props.data?.lastInteractionDate)
      ),
      React.createElement('div', { className: "insight-pill" },
        React.createElement('div', { className: "insight-icon-container" }, 
          React.createElement('svg', { viewBox: "0 0 24 24", fill: "#3B82F6" },
            React.createElement('path', { d: "M12 3L14.5 9.5L21 12L14.5 14.5L12 21L9.5 14.5L3 12L9.5 9.5L12 3Z" })
          )
        ),
        React.createElement('div', { className: "insight-text" }, props.data?.insight)
      )
    )
  );
}

const ConnectedComponent = Tooljet.connectComponent(IZOInteractionTimeline);
if (!window.tooljetRoot) window.tooljetRoot = ReactDOM.createRoot(document.body);
window.tooljetRoot.render(React.createElement(ConnectedComponent));
